/* Look up a guide by slug (used by the #guide/<slug> hash router). */
/** @param {string} slug @returns {?{slug:string,title:string,summary:string,readMin:number,body:string}} */
function guideBySlug(slug){
  for (var i = 0; i < GUIDES.length; i++){ if (GUIDES[i].slug === slug) return GUIDES[i]; }
  return null;
}

if (typeof module !== 'undefined' && module.exports){ module.exports = { GUIDES: GUIDES, guideBySlug: guideBySlug }; }
